
"use client"

import React, { useState } from 'react';
import { Crown, Zap, TrendingUp, Newspaper, ArrowRight, Loader2, CreditCard, ShieldCheck, Phone, ExternalLink } from 'lucide-react';
import { Button } from '@/components/ui/button';
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogDescription,
} from "@/components/ui/dialog";
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs";
import { useUser, useFirestore } from '@/firebase';
import { doc, updateDoc, serverTimestamp } from 'firebase/firestore';
import { toast } from '@/hooks/use-toast';

interface PaywallProps {
  isOpen: boolean;
  onClose: () => void;
}

export const Paywall = ({ isOpen, onClose }: PaywallProps) => {
  const { user } = useUser();
  const db = useFirestore();
  const [isProcessing, setIsProcessing] = useState(false);
  const [step, setStep] = useState<'offer' | 'checkout'>('offer');

  const handleCheckout = async () => {
    if (!user || !db) return;
    setIsProcessing(true);
    
    // Simulated institutional verification gateway
    setTimeout(async () => {
      try {
        const profileRef = doc(db, 'users', user.uid, 'profile', user.uid);
        await updateDoc(profileRef, { 
          isSubscribed: true,
          updatedAt: serverTimestamp()
        });
        toast({ title: "VIP Activated", description: "Terminal upgraded to VIP Institutional status." });
        onClose();
        setStep('offer');
      } catch (e) {
        toast({ title: "Error", description: "Failed to update terminal status.", variant: "destructive" });
      } finally {
        setIsProcessing(false);
      }
    }, 2000);
  };

  const features = [
    { icon: <Zap className="h-5 w-5 text-primary" />, title: "Unlimited Signals", desc: "Unlock every AI pulse signal instantly with no limits." },
    { icon: <TrendingUp className="h-5 w-5 text-accent" />, title: "Pips Tracker", desc: "Analyze your performance history with the institutional tracker." },
    { icon: <Newspaper className="h-5 w-5 text-success" />, title: "Technical Hub", desc: "Full access to advanced sentiment gauges and news feeds." },
    { icon: <Crown className="h-5 w-5 text-gold" />, title: "Elite Support", desc: "Direct priority assistance for professional members." },
  ];

  return (
    <Dialog open={isOpen} onOpenChange={(open) => {
      if (!open && !isProcessing) {
        onClose();
        setStep('offer');
      }
    }}>
      <DialogContent className="sm:max-w-lg border-white/5 glassmorphism p-0 overflow-hidden shadow-2xl">
        {step === 'offer' ? (
          <div className="flex flex-col">
            <div className="p-8 space-y-8">
              <div className="flex flex-col items-center text-center space-y-4">
                <div className="h-20 w-20 rounded-[2rem] bg-amber-500/10 border border-amber-500/30 flex items-center justify-center animate-pulse-gold">
                  <Crown className="h-10 w-10 text-amber-500" />
                </div>
                
                <DialogHeader>
                  <DialogTitle className="text-4xl font-black tracking-tighter bg-clip-text text-transparent bg-gradient-to-r from-amber-400 to-amber-600">
                    VIP TERMINAL
                  </DialogTitle>
                  <DialogDescription className="text-muted-foreground font-black uppercase tracking-widest text-[10px] pt-2">
                    Pay once to unlock global institutional access
                  </DialogDescription>
                </DialogHeader>
              </div>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                {features.map((f, i) => (
                  <div key={i} className="p-4 rounded-2xl bg-white/5 border border-white/5 space-y-2">
                    <div className="flex items-center gap-3">
                      {f.icon}
                      <span className="text-[10px] font-black uppercase tracking-tight">{f.title}</span>
                    </div>
                    <p className="text-[9px] text-muted-foreground leading-relaxed font-medium">{f.desc}</p>
                  </div>
                ))}
              </div>

              <div className="w-full space-y-6 pt-6 border-t border-white/10">
                <div className="flex items-center justify-between">
                  <div className="space-y-1">
                    <p className="text-[10px] font-black text-muted-foreground uppercase tracking-widest">Subscription</p>
                    <p className="text-3xl font-black text-white">$25<span className="text-xs font-medium text-muted-foreground/50 ml-1">/Mo</span></p>
                  </div>
                  <Button className="h-14 px-10 text-md font-black bg-amber-500 hover:bg-amber-600 text-black rounded-2xl animate-pulse-gold" onClick={() => setStep('checkout')}>
                    Upgrade Now <ArrowRight className="ml-2 h-5 w-5" />
                  </Button>
                </div>
                <p className="text-[9px] text-center text-muted-foreground/40 font-bold uppercase tracking-[0.3em]">Hassan Deeb Institutional Trading</p>
              </div>
            </div>
          </div>
        ) : (
          <div className="p-8 space-y-8 animate-in slide-in-from-bottom-4 duration-500">
            <div className="flex items-center gap-4 border-b border-white/5 pb-6">
              <div className="h-12 w-12 rounded-xl bg-primary/10 flex items-center justify-center">
                <ShieldCheck className="h-6 w-6 text-primary" />
              </div>
              <div className="space-y-1">
                <h3 className="text-xl font-black uppercase tracking-tighter">Gateway Activation</h3>
                <p className="text-[9px] font-bold text-muted-foreground uppercase tracking-widest">Activate $25.00 VIP Plan</p>
              </div>
            </div>
            
            <Tabs defaultValue="card" className="w-full">
              <TabsList className="grid w-full grid-cols-2 bg-white/5 border border-white/10 h-14 p-1.5 rounded-2xl">
                <TabsTrigger value="card" className="font-black uppercase text-[10px] tracking-widest rounded-xl">Visa / Master</TabsTrigger>
                <TabsTrigger value="manual" className="font-black uppercase text-[10px] tracking-widest rounded-xl">Wish / Suyool</TabsTrigger>
              </TabsList>
              
              <TabsContent value="card" className="space-y-6 pt-6">
                <div className="p-6 rounded-2xl border border-white/10 bg-white/5 space-y-4">
                  <div className="flex justify-between items-center">
                    <span className="text-xs font-black uppercase tracking-widest text-muted-foreground">Activation Fee</span>
                    <span className="text-lg font-black">$25.00</span>
                  </div>
                  <div className="h-12 w-full rounded-xl border border-white/10 bg-black/40 flex items-center px-4 gap-4">
                    <CreditCard className="h-4 w-4 text-muted-foreground/50" />
                    <span className="text-sm font-mono text-muted-foreground tracking-widest">•••• •••• •••• ••••</span>
                  </div>
                </div>

                <Button 
                  className="w-full h-14 text-md font-black bg-primary hover:bg-primary/90 text-white rounded-2xl shadow-xl" 
                  onClick={handleCheckout} 
                  disabled={isProcessing}
                >
                  {isProcessing ? <Loader2 className="h-5 w-5 animate-spin mr-2" /> : 'Confirm Activation'}
                </Button>
              </TabsContent>
              
              <TabsContent value="manual" className="space-y-6 pt-6">
                <div className="space-y-4">
                  <div className="p-6 rounded-2xl border border-white/10 bg-white/5 space-y-6">
                    <div className="space-y-2">
                      <p className="text-[10px] font-black uppercase text-primary tracking-widest">Wish Money Transfer</p>
                      <div className="flex items-center justify-between">
                         <p className="text-lg font-black font-mono tracking-tighter">+961 81 438 747</p>
                         <Phone className="h-4 w-4 text-primary" />
                      </div>
                    </div>
                    
                    <div className="pt-4 border-t border-white/5 space-y-2">
                      <p className="text-[10px] font-black uppercase text-accent tracking-widest">Suyool Payment Link</p>
                      <a 
                        href="https://www.suyool.com/RQIUZ5Znf2xPpJ95JcuK5" 
                        target="_blank" 
                        rel="noopener noreferrer"
                        className="flex items-center justify-between p-3 rounded-xl bg-accent/10 border border-accent/20 hover:border-accent/50 transition-all"
                      >
                        <span className="text-[10px] font-black uppercase tracking-tight text-accent">Open Suyool Link</span>
                        <ExternalLink className="h-4 w-4 text-accent" />
                      </a>
                    </div>
                  </div>

                  <Button 
                    className="w-full h-14 text-[11px] font-black bg-success hover:bg-success/90 text-black uppercase tracking-widest rounded-2xl" 
                    onClick={handleCheckout} 
                    disabled={isProcessing}
                  >
                    Confirm Payment Dispatched
                  </Button>
                </div>
              </TabsContent>
            </Tabs>
          </div>
        )}
        <div className="bg-black/40 p-4 border-t border-white/5 text-center">
          <p className="text-[9px] font-bold text-muted-foreground/30 uppercase tracking-[0.5em]">Powered by Hassan Deeb</p>
        </div>
      </DialogContent>
    </Dialog>
  );
};
